mapper.select:
SELECT service_type_code AS serviceTypeCode, service_type_name AS serviceTypeName, COUNT(*) AS orderCount, SUM(CASE WHEN status = 'COMPLETED' THEN 1 ELSE 0 END) AS completedCount, COALESCE(SUM(estimated_price), 0) AS totalAmount, COALESCE(AVG(rating), 0) AS averageRating FROM t_order WHERE deleted = 0
AND create_time >= #{startDate}
AND create_time <= #{endDate}
AND service_type_code = #{serviceTypeCode}
GROUP BY service_type_code, service_type_name ORDER BY orderCount DESC

SELECT service_type_code AS serviceTypeCode, service_type_name AS serviceTypeName, COUNT(*) AS orderCount, SUM(CASE WHEN status IN ('SERVICE_COMPLETED', 'EVALUATED', 'SETTLED') THEN 1 ELSE 0 END) AS completedCount, COALESCE(SUM(estimated_price), 0) AS totalAmount FROM t_order WHERE deleted = 0
AND provider_id = #{providerId}
GROUP BY service_type_code, service_type_name ORDER BY orderCount DESC

SELECT order_source AS orderSource, COUNT(*) AS count FROM t_order WHERE deleted = 0
AND provider_id = #{providerId}
GROUP BY order_source ORDER BY count DESC

SELECT s.staff_id AS staffId, s.staff_name AS staffName, p.provider_name AS providerName, COUNT(o.order_id) AS orderCount, SUM(CASE WHEN o.status IN ('SERVICE_COMPLETED', 'EVALUATED', 'SETTLED') THEN 1 ELSE 0 END) AS serviceCount FROM t_staff s LEFT JOIN t_order o ON s.staff_id = o.staff_id AND o.deleted = 0 LEFT JOIN t_provider p ON s.provider_id = p.provider_id WHERE s.deleted = 0
AND s.provider_id = #{providerId}
GROUP BY s.staff_id, s.staff_name, p.provider_name ORDER BY orderCount DESC LIMIT #{limit}
